class AuthService {
    constructor() {
      if (!AuthService.instance) {
        this.user = null; // Holds the currently logged-in user
        this.token = null; // Optional: if using tokens for authentication
        AuthService.instance = this;
      }
      return AuthService.instance;
    }
  
    async login(email, password) {
      try {
        const response = await fetch("http://localhost:5000/login", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ email, password }),
        });
  
        if (!response.ok) {
          throw new Error("Login failed");
        }
  
        const data = await response.json();
        this.user = data.user; // Example: { id, name, email }
        this.token = data.token; // If applicable
        return this.user;
      } catch (error) {
        console.error("Error during login:", error);
        throw error;
      }
    }
  
    logout() {
      this.user = null;
      this.token = null;
    }
  
    getUser() {
      return this.user;
    }
  }
  
  const instance = new AuthService();
  Object.freeze(instance); // Ensures it's a true singleton
  export default instance;
